    loadingEl.classList.add("hidden");
    setStatus("Ready");
    console.log("Application ready");
  } catch (err) {
    console.error("Application error:", err);
    setStatus(`Error: ${err instanceof Error ? err.message : String(err)}`);
  }
}

main();

